using System;
using System.IO;
using System.Linq;
using System.Text.RegularExpressions;
using Xunit;

namespace TestProject.Tests;

/// <summary>
/// Verifies the file-level mechanics of relocating
/// <c>FileServiceOptions</c> from the root <c>TestProject</c> namespace into
/// <c>TestProject.Configuration</c>.
///
/// These tests inspect source files directly (rather than compiling against the
/// relocated type) so they remain compilable both before and after the move. The
/// assertions describe the expected end state of the repository:
/// <list type="bullet">
/// <item>The old <c>FileServiceOptions.cs</c> at the repository root is deleted.</item>
/// <item>A new <c>Configuration/FileServiceOptions.cs</c> exists and declares
/// <c>namespace TestProject.Configuration;</c>.</item>
/// <item><c>Program.cs</c> references the new namespace via a <c>using</c>
/// directive or a fully-qualified name, and no longer uses the old root-qualified
/// type name.</item>
/// <item><c>Services/FileService.cs</c> references the new namespace so its
/// <c>IOptions&lt;FileServiceOptions&gt;</c> constructor parameter resolves.</item>
/// </list>
/// </summary>
public class FileServiceOptionsNamespaceTests
{
    // File-scoped namespace declarations the relocation is expected to produce/consume.
    private const string ConfigurationUsingPattern = @"using\s+TestProject\.Configuration\s*;";
    private const string FullyQualifiedPattern = @"TestProject\.Configuration\.FileServiceOptions";
    // Matches the OLD root-qualified name. This deliberately does NOT match
    // "TestProject.Configuration.FileServiceOptions" because a '.' (not
    // '.FileServiceOptions') follows "TestProject".
    private const string OldRootQualifiedPattern = @"TestProject\.FileServiceOptions\b";

    /// <summary>
    /// Walks up from the test output directory to the folder containing
    /// <c>TestProject.csproj</c> (and <c>Program.cs</c>), which is the repo root.
    /// </summary>
    private static string RepoRoot
    {
        get
        {
            var dir = new DirectoryInfo(AppContext.BaseDirectory);
            while (dir is not null)
            {
                if (File.Exists(Path.Combine(dir.FullName, "TestProject.csproj")) &&
                    File.Exists(Path.Combine(dir.FullName, "Program.cs")))
                {
                    return dir.FullName;
                }

                dir = dir.Parent;
            }

            throw new DirectoryNotFoundException(
                "Could not locate the repository root (folder containing both " +
                "TestProject.csproj and Program.cs) by walking up from " +
                AppContext.BaseDirectory + ".");
        }
    }

    private static string ReadSource(string relativePath) =>
        File.ReadAllText(Path.Combine(RepoRoot, relativePath));

    // =====================================================================
    // File relocation: old file removed, new file present
    // =====================================================================

    [Fact]
    public void OldRootLevel_FileServiceOptions_File_IsDeleted()
    {
        var oldPath = Path.Combine(RepoRoot, "FileServiceOptions.cs");

        Assert.False(File.Exists(oldPath),
            $"The old root-level '{oldPath}' must be deleted because the type " +
            "now lives under Configuration/FileServiceOptions.cs.");
    }

    [Fact]
    public void New_Configuration_FileServiceOptions_File_Exists()
    {
        var newPath = Path.Combine(RepoRoot, "Configuration", "FileServiceOptions.cs");

        Assert.True(File.Exists(newPath),
            "Expected Configuration/FileServiceOptions.cs to exist after the move.");
    }

    [Fact]
    public void New_Configuration_File_DeclaresTestProjectConfigurationNamespace()
    {
        var newPath = Path.Combine(RepoRoot, "Configuration", "FileServiceOptions.cs");
        Assert.True(File.Exists(newPath),
            "Cannot verify namespace: Configuration/FileServiceOptions.cs is missing.");

        var source = File.ReadAllText(newPath);

        // File-scoped namespace declaration as specified by the task.
        Assert.Matches(
            @"namespace\s+TestProject\.Configuration\s*;",
            source);

        // The new file must NOT declare the old root namespace.
        Assert.DoesNotMatch(
            @"namespace\s+TestProject\s*\{",
            source);
        Assert.DoesNotMatch(
            @"namespace\s+TestProject\s*;",
            source);
    }

    [Fact]
    public void New_Configuration_File_DeclaresTheHomeDirectoryClass()
    {
        var newPath = Path.Combine(RepoRoot, "Configuration", "FileServiceOptions.cs");
        Assert.True(File.Exists(newPath));

        var source = File.ReadAllText(newPath);

        Assert.Matches(@"public\s+class\s+FileServiceOptions\b", source);
        Assert.Matches(@"HomeDirectory\b", source);
    }

    [Fact]
    public void Repo_ContainsExactlyOne_FileServiceOptions_SourceFile()
    {
        // Build artifact directories must be ignored; only the handwritten source counts.
        var all = Directory.GetFiles(RepoRoot, "FileServiceOptions.cs", SearchOption.AllDirectories)
            .Where(p => !IsUnderBuildArtifacts(p))
            .ToArray();

        var relative = string.Join(", ", all.Select(p => Path.GetRelativePath(RepoRoot, p)));

        Assert.True(all.Length == 1,
            $"Expected exactly one FileServiceOptions.cs source file, found {all.Length}: [{relative}].");
        Assert.Equal(
            Path.Combine("Configuration", "FileServiceOptions.cs"),
            Path.GetRelativePath(RepoRoot, all[0]));
    }

    private static bool IsUnderBuildArtifacts(string fullPath)
    {
        var parts = fullPath.Split(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
        return parts.Contains("bin") || parts.Contains("obj");
    }

    // =====================================================================
    // Program.cs references the relocated namespace
    // =====================================================================

    [Fact]
    public void Program_ReferencesTestProjectConfigurationNamespace()
    {
        var source = ReadSource("Program.cs");

        var hasUsing = Regex.IsMatch(source, ConfigurationUsingPattern);
        var hasFullyQualified = Regex.IsMatch(source, FullyQualifiedPattern);

        Assert.True(hasUsing || hasFullyQualified,
            "Program.cs must reference TestProject.Configuration either via a " +
            "'using TestProject.Configuration;' directive or by using the " +
            "fully-qualified 'TestProject.Configuration.FileServiceOptions' name " +
            "in the Configure<FileServiceOptions>(...) call.");
    }

    [Fact]
    public void Program_DoesNotReferenceOldRootQualifiedType()
    {
        var source = ReadSource("Program.cs");

        Assert.DoesNotMatch(OldRootQualifiedPattern, source);
    }

    // =====================================================================
    // Services/FileService.cs references the relocated namespace
    // =====================================================================

    [Fact]
    public void FileService_ReferencesTestProjectConfigurationNamespace()
    {
        var source = ReadSource(Path.Combine("Services", "FileService.cs"));

        var hasUsing = Regex.IsMatch(source, ConfigurationUsingPattern);
        var hasFullyQualified = Regex.IsMatch(source, FullyQualifiedPattern);

        Assert.True(hasUsing || hasFullyQualified,
            "Services/FileService.cs must reference TestProject.Configuration " +
            "(its constructor takes IOptions<FileServiceOptions>) via a 'using " +
            "TestProject.Configuration;' directive or a fully-qualified name.");
    }
}

